sys_ui_action.script:
// AIROP - Run Assessment Now
// Created via Studio to ensure correct scope association

(function() {

    // Step 1: Check if another assessment is already running
    var running = new GlideRecord('x_snc_airop_assessment_run');
    running.addQuery('status', 'running');
    running.setLimit(1);
    running.query();
    if (running.next()) {
        gs.addErrorMessage('An assessment is already running: ' +
            running.getValue('name') +
            '. Only one assessment can run at a time. Please wait for it to complete.');
        action.setRedirectURL('x_snc_airop_assessment_run_list.do');
        return;
    }

    // Step 2: Check at least one module is enabled
    var propMap = {
        'ITSM':            'x_snc_airop.run_itsm',
        'ITOM':            'x_snc_airop.run_itom',
        'CMDB':            'x_snc_airop.run_cmdb',
        'HRSD':            'x_snc_airop.run_hrsd',
        'EMPLOYEE_CENTER': 'x_snc_airop.run_employee_center',
        'CSM':             'x_snc_airop.run_csm',
        'FIELD_SERVICE':   'x_snc_airop.run_field_service',
        'TSOM':            'x_snc_airop.run_tsom',
        'GRC':             'x_snc_airop.run_grc',
        'SPM':             'x_snc_airop.run_spm',
        'ITSM_PRO':        'x_snc_airop.run_itsm_pro',
        'PLATFORM':        'x_snc_airop.run_platform',
        'INTEGRATION':     'x_snc_airop.run_integration',
        'VIRTUAL_AGENT':   'x_snc_airop.run_virtual_agent'
    };
    var enabledModules = [];
    for (var mod in propMap) {
        if (gs.getProperty(propMap[mod], 'false') === 'true') {
            enabledModules.push(mod);
        }
    }
    if (enabledModules.length === 0) {
        gs.addErrorMessage('No modules are enabled. Please enable at least one module in Configuration before running an assessment.');
        action.setRedirectURL('x_snc_airop_assessment_run_list.do');
        return;
    }

    // Step 3: Create the run record immediately with status = running
    var runName = 'AI Readiness Checks for: ' + enabledModules.join(', ');
    var runGr = new GlideRecord('x_snc_airop_assessment_run');
    runGr.setWorkflow(false);
    runGr.autoSysFields(false);
    runGr.setValue('name',             runName);
    runGr.setValue('run_date',         new GlideDateTime());
    runGr.setValue('triggered_by',     gs.getUserID());
    runGr.setValue('status',           'running');
    runGr.setValue('environment_type', 'unknown');
    runGr.setValue('modules_scanned',  enabledModules.join(', '));
    var runId = runGr.insert();

    if (!runId) {
        gs.addErrorMessage('Failed to create assessment run record. Check Script Execution Log for details.');
        action.setRedirectURL('x_snc_airop_assessment_run_list.do');
        return;
    }
    gs.info('[AIROP] Run record created: ' + runId);

    // Step 4: Fire the scheduled job immediately
    var schedJob = new GlideRecord('sysauto_script');
    schedJob.addQuery('name', 'AIROP Scheduled Assessment');
    schedJob.setLimit(1);
    schedJob.query();
    if (schedJob.next()) {
        schedJob.setValue('next_action', new GlideDateTime());
        schedJob.setValue('active',      true);
        schedJob.update();
        gs.info('[AIROP] Scheduled job fired for run: ' + runId);
    } else {
        gs.error('[AIROP] Scheduled job not found - checks will not execute');
    }

    // Step 5: Redirect to the new run record
    gs.addInfoMessage('Assessment started: ' + runName +
        '. Refresh this record in a few seconds to see results.');
    action.setRedirectURL('x_snc_airop_assessment_run.do?sys_id=' + runId);

})();
